using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_d0254cff2bc647f7bd17e9354ee2b61f.Components;

public sealed class InfiniteScrollListInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/InfiniteScrollList.razor.js";
    internal const string InitMethod = "initialize";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public InfiniteScrollListInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync(ElementReference sentinel, DotNetObjectReference<object> dotNetRef)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, sentinel, dotNetRef);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

const ON_SENTINEL_VISIBLE = "OnSentinelVisible";

class InfiniteScrollObserver {
    #dotNetRef;
    #observer;

    constructor(sentinel, dotNetRef) {
        this.#dotNetRef = dotNetRef;
        this.#observer = new IntersectionObserver(
            (entries) => this.#handleIntersection(entries),
            { rootMargin: "200px" }
        );
        this.#observer.observe(sentinel);
    }

    async #handleIntersection(entries) {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                try {
                    await this.#dotNetRef.invokeMethodAsync(ON_SENTINEL_VISIBLE);
                } catch { /* circuit disconnected */ }
            }
        }
    }

    dispose() {
        this.#observer.disconnect();
    }
}

let instance;

export function initialize(sentinel, dotNetRef) {
    instance = new InfiniteScrollObserver(sentinel, dotNetRef);
}

export function dispose() {
    instance?.dispose();
    instance = null;
}

